class Solution:
    def deserialize(self, s: str) -> NestedInteger:
        if s[0] != '[':
            return NestedInteger(int(s))
        st, cur = [], None
        num = ''
        for c in s:
            if c == '[':
                if cur is not None: st.append(cur)
                cur = NestedInteger()
            elif c == ']':
                if num:
                    cur.add(NestedInteger(int(num))); num = ''
                if st:
                    parent = st.pop(); parent.add(cur); cur = parent
            elif c == ',':
                if num:
                    cur.add(NestedInteger(int(num))); num = ''
            else:
                num += c
        return cur

