class Solution {
public:
    NestedInteger deserialize(string s) {
        if (s.empty()) return NestedInteger();
        if (s[0] != '[') return NestedInteger(stoi(s));
        stack<NestedInteger> st;
        NestedInteger cur;
        int num = 0; bool neg = false, inNum = false;
        for (char c : s) {
            if (c == '[') { if (inNum || !st.empty() || cur.isInteger()==false && !cur.getList().empty()) st.push(cur); cur = NestedInteger(); inNum=false; }
            else if (c == ']') { if (inNum) { cur.add(NestedInteger(num)); num=0; inNum=false; } if (!st.empty()) { NestedInteger p = st.top(); st.pop(); p.add(cur); cur = p; } }
            else if (c == ',') { if (inNum) { cur.add(NestedInteger(num)); num=0; inNum=false; } }
            else if (c == '-') neg = true;
            else { inNum = true; num = num*10 + (c-'0'); if (neg) { num = -num; neg=false; } }
        }
        return cur;
    }
};

